#include<bits/stdc++.h>
using namespace std;
const int N = 1e5+5;
int n,a[N],cnt,st[N][25],lg[N],ans=0x3f3f3f3f;
int GCD(int x,int y){
    if(x<y)swap(x,y);
    if(y==0)return x;
    return GCD(y,x%y);
}
void init(){
    lg[1]=1;
    for(int i=2;i<=n;i++)lg[i]=lg[i/2]+1;
    for(int i=1;i<=n;i++)st[i][0]=a[i];
    for(int j=1;j<=25;j++)
        for(int i=1;i+(1<<j)-1<=n;i++)
            st[i][j]=GCD(st[i][j-1],st[i+(1<<(j-1))][j-1]);
}
int Count(int l,int r){
    int g=lg[r-l+1];
    return GCD(st[l][g-1],st[r-(1<<(g-1))+1][g-1]);
}
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i];
        cnt+=(a[i]==1);
    }
    if(cnt){cout<<n-cnt;return 0;}
    init();
    for(int l=1,r=1;r<=n;r++){
        while(l<r&&Count(l+1,r)==1)l++;
        if(Count(l,r)==1)ans=min(ans,r-l);
    }
    if(ans==0x3f3f3f3f)cout<<"-1";
    else cout<<n+ans-1;
    return 0;
}
